import{_ as e,o as i,c as s,aw as a}from"./chunks/framework.x-9C0vN4.js";const t=JSON.parse('{"title":"ADR 023: P2P Connection Gater Blocklist","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ADR 023: P2P Connection Gater Blocklist | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"adr/adr-023-p2p-gater-ttl.md","filePath":"adr/adr-023-p2p-gater-ttl.md","lastUpdated":1776776681000}');const n=e({name:"adr/adr-023-p2p-gater-ttl.md"},[["render",function(e,t,n,l,o,r){return i(),s("div",null,[...t[0]||(t[0]=[a('<h1 id="adr-023-p2p-connection-gater-blocklist" tabindex="-1">ADR 023: P2P Connection Gater Blocklist <a class="header-anchor" href="#adr-023-p2p-connection-gater-blocklist" aria-label="Permalink to &quot;ADR 023: P2P Connection Gater Blocklist&quot;">​</a></h1><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li>2026-04-20: Initial draft</li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p><code>pkg/p2p/Client</code> uses <code>conngater.BasicConnectionGater</code> from go-libp2p to enforce peer-level allow/block rules. The gater is constructed with the node&#39;s persistent datastore:</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// pkg/p2p/client.go:85</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gater, err </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> conngater.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">NewBasicConnectionGater</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ds)</span></span></code></pre></div><p><code>BasicConnectionGater</code> writes every <code>BlockPeer</code> call to the datastore under its own internal keys. These entries <strong>survive node restarts indefinitely</strong>. Once a peer ID lands in the blocklist — regardless of the reason — the node will refuse all outbound and inbound connections to that peer forever, with no way to recover short of wiping the entire datastore.</p><p>This became a production incident on the <code>edennet-2</code> testnet (see evstack/ev-node#3267): a fullnode accumulated stale block entries, which caused every binary builders nodes to be rejected by the local gater. Header sync never initialized, and the node fell back to unstable and latency prone DA-only sync.</p><p>Two distinct categories of blocks exist today but are treated identically:</p><table tabindex="0"><thead><tr><th>Category</th><th>Source</th><th>Expected lifetime</th></tr></thead><tbody><tr><td><strong>Config blocks</strong></td><td><code>p2p.blocked_peers</code> in node config</td><td>As long as the entry stays in config</td></tr><tr><td><strong>Dynamic blocks</strong></td><td>Written by internal logic or operator tooling</td><td>Should expire; intent may be forgotten</td></tr></tbody></table><p>There is currently no way to:</p><ul><li>Distinguish the two categories in the datastore.</li><li>Set a TTL or expiry on any block entry.</li><li>Inspect which peers are blocked at runtime or at startup.</li><li>Clear dynamic blocks without wiping the full datastore.</li><li>Observe blocklist state via monitoring tooling.</li></ul><h2 id="alternative-approaches" tabindex="-1">Alternative Approaches <a class="header-anchor" href="#alternative-approaches" aria-label="Permalink to &quot;Alternative Approaches&quot;">​</a></h2><h3 id="a-—-in-memory-gater-no-persistence" tabindex="-1">A — In-memory gater (no persistence) <a class="header-anchor" href="#a-—-in-memory-gater-no-persistence" aria-label="Permalink to &quot;A — In-memory gater (no persistence)&quot;">​</a></h3><p>Pass <code>nil</code> to <code>NewBasicConnectionGater</code>. All block state is ephemeral; config-driven blocks are re-applied on every startup from <code>p2p.blocked_peers</code>.</p><p><strong>Pros:</strong> Zero risk of stale state. Simple implementation.</p><p><strong>Cons:</strong> Defeats the purpose of a persistent gater for genuinely malicious peers. A node that dynamically bans a peer for misbehavior loses the ban on restart, potentially reconnecting to the same bad actor immediately. Also, the upstream <code>BasicConnectionGater</code> API has no in-memory shortcut that skips its own datastore writes when given <code>nil</code> in all versions — it falls back to an in-memory map, but this is an implementation detail we cannot rely on across library upgrades.</p><h3 id="b-—-wipe-gater-namespace-on-startup-before-loading-config-blocks" tabindex="-1">B — Wipe gater namespace on startup before loading config blocks <a class="header-anchor" href="#b-—-wipe-gater-namespace-on-startup-before-loading-config-blocks" aria-label="Permalink to &quot;B — Wipe gater namespace on startup before loading config blocks&quot;">​</a></h3><p>On every start, delete the gater&#39;s datastore namespace, then re-apply only the blocks listed in config.</p><p><strong>Pros:</strong> Config blocks always reflect current intent. No stale entries.</p><p><strong>Cons:</strong> All dynamic blocks (e.g., misbehaviour bans applied at runtime) are lost on every restart, making runtime banning useless. Also requires knowing the internal datastore key prefix used by <code>BasicConnectionGater</code>, which is a private implementation detail.</p><h3 id="c-—-ttl-based-wrapper-with-startup-reconciliation-and-observability-chosen" tabindex="-1">C — TTL-based wrapper with startup reconciliation and observability (chosen) <a class="header-anchor" href="#c-—-ttl-based-wrapper-with-startup-reconciliation-and-observability-chosen" aria-label="Permalink to &quot;C — TTL-based wrapper with startup reconciliation and observability (chosen)&quot;">​</a></h3><p>Wrap <code>BasicConnectionGater</code> in a thin <code>TTLConnectionGater</code> that:</p><ol><li>Stores block entries with an expiry timestamp in a separate ev-node-owned datastore namespace (not the gater&#39;s own namespace).</li><li>At startup, reads the TTL store, discards expired entries, and calls <code>BlockPeer</code> only for live entries — plus re-applies config blocks (with no expiry).</li><li>Provides a periodic background sweep to unblock peers whose TTL has elapsed at runtime.</li><li>Exposes Prometheus metrics for the current blocklist state, including per-peer labels.</li></ol><p>This keeps persistence for intentional runtime bans, gives config blocks permanent status, automatically heals nodes that accumulated stale entries, and makes the blocklist observable.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Implement <strong>Option C</strong>: a <code>TTLConnectionGater</code> wrapper around <code>BasicConnectionGater</code> with a default TTL of <strong>24 hour</strong> for dynamic blocks, permanent status for config-sourced blocks, and Prometheus metrics exposing the full blocklist state.</p><p>The implementation is entirely within the <code>pkg/p2p</code> package. No external API or consensus changes are required.</p><h2 id="detailed-design" tabindex="-1">Detailed Design <a class="header-anchor" href="#detailed-design" aria-label="Permalink to &quot;Detailed Design&quot;">​</a></h2><h3 id="data-model" tabindex="-1">Data model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data model&quot;">​</a></h3><p>A new datastore namespace <code>/p2p/gater/ttl/</code> stores JSON-encoded records keyed by peer ID:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/p2p/gater/ttl/&lt;peerID&gt;  →  {&quot;expires_at&quot;: &lt;unix-seconds&gt;, &quot;reason&quot;: &quot;&lt;string&gt;&quot;, &quot;source&quot;: &quot;&lt;config|dynamic&gt;&quot;}</span></span></code></pre></div><p><code>expires_at = 0</code> is a sentinel meaning &quot;permanent&quot; (used for config blocks).</p><p>The existing <code>BasicConnectionGater</code> datastore entries (written under its own private namespace) will be <strong>ignored going forward</strong>. On first startup after the upgrade, the TTLConnectionGater will not find its own records and will start fresh — effectively clearing any stale legacy entries automatically.</p><h3 id="ttlconnectiongater-struct" tabindex="-1"><code>TTLConnectionGater</code> struct <a class="header-anchor" href="#ttlconnectiongater-struct" aria-label="Permalink to &quot;`TTLConnectionGater` struct&quot;">​</a></h3><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// pkg/p2p/ttl_gater.go</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> blockSource</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> string</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    blockSourceConfig</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  blockSource</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;config&quot;</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    blockSourceDynamic</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> blockSource</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;dynamic&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> blockRecord</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ExpiresAt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int64</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">       `json:&quot;expires_at&quot;`</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // Unix seconds; 0 = permanent</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Reason    </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      `json:&quot;reason&quot;`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Source    </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">blockSource</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> `json:&quot;source&quot;`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> TTLConnectionGater</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    inner      </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">conngater</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BasicConnectionGater</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ds         </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">datastore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Datastore</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    defaultTTL </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Duration</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    metrics    </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GaterMetrics</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    logger     </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zerolog</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Logger</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mu         </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">RWMutex</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="key-methods" tabindex="-1">Key methods <a class="header-anchor" href="#key-methods" aria-label="Permalink to &quot;Key methods&quot;">​</a></h3><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// BlockPeerWithTTL blocks a peer for the given duration and persists the record.</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Use ttl=0 for a permanent block (config-driven).</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">g </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TTLConnectionGater</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BlockPeerWithTTL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">id</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> peer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">ttl</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Duration</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">reason</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">source</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> blockSource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">error</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// UnblockPeer removes a peer from the blocklist immediately.</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">g </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TTLConnectionGater</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">UnblockPeer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">id</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> peer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">error</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ListBlocked returns all currently active block records.</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">g </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TTLConnectionGater</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ListBlocked</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">peer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">blockRecord</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// InterceptPeerDial delegates to inner gater (which is registered with libp2p).</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// TTLConnectionGater implements network.ConnectionGater by delegation.</span></span></code></pre></div><h3 id="startup-reconciliation" tabindex="-1">Startup reconciliation <a class="header-anchor" href="#startup-reconciliation" aria-label="Permalink to &quot;Startup reconciliation&quot;">​</a></h3><p>In <code>NewClient</code> (or a dedicated <code>loadGaterState</code> helper called from <code>Start</code>):</p><ol><li>Iterate all keys under <code>/p2p/gater/ttl/</code>.</li><li>For each record: <ul><li>If <code>expires_at != 0</code> and <code>now &gt; expires_at</code>: delete the datastore key and skip.</li><li>Otherwise: call <code>inner.BlockPeer(id)</code>.</li></ul></li><li>For each peer in <code>conf.BlockedPeers</code>: call <code>BlockPeerWithTTL(id, 0, &quot;config&quot;, blockSourceConfig)</code> — permanent, overwrites any existing TTL entry.</li><li>For each peer in <code>conf.AllowedPeers</code> (currently <code>UnblockPeer</code> targets): if a TTL record exists, delete it and call <code>inner.UnblockPeer(id)</code>.</li><li>After reconciliation, refresh all Prometheus metrics gauges to reflect current state.</li></ol><h3 id="background-sweep" tabindex="-1">Background sweep <a class="header-anchor" href="#background-sweep" aria-label="Permalink to &quot;Background sweep&quot;">​</a></h3><p>A goroutine started in <code>Client.Start</code> runs on a configurable interval (default: <strong>5 min</strong>):</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">g </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TTLConnectionGater</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sweepExpired</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">ctx</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> context</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Context</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">interval</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Duration</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>On each tick:</p><ul><li>Load all TTL records from the datastore.</li><li>For any expired record: delete the datastore key and call <code>inner.UnblockPeer(id)</code>.</li><li>Update Prometheus metrics to reflect the post-sweep state.</li><li>Log the number of entries swept at <code>DEBUG</code> level.</li></ul><h3 id="startup-diagnostic-logging" tabindex="-1">Startup diagnostic logging <a class="header-anchor" href="#startup-diagnostic-logging" aria-label="Permalink to &quot;Startup diagnostic logging&quot;">​</a></h3><p>After reconciliation, log at <code>INFO</code> level:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>p2p gater loaded: 3 permanent blocks (config), 1 dynamic block (expires in 47m), 0 expired entries pruned</span></span></code></pre></div><p>For each blocked peer, log at <code>DEBUG</code> level: peer ID, expiry time, reason, source.</p><h3 id="prometheus-metrics" tabindex="-1">Prometheus metrics <a class="header-anchor" href="#prometheus-metrics" aria-label="Permalink to &quot;Prometheus metrics&quot;">​</a></h3><p>Add a <code>GaterMetrics</code> struct to <code>pkg/p2p/metrics.go</code> alongside the existing <code>Metrics</code>:</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// GaterMetrics contains metrics for the TTL connection gater blocklist.</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> GaterMetrics</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Total number of currently blocked peers.</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    BlockedPeersTotal </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">metrics</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Gauge</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Per-peer blocked status. Label peer_id identifies the peer; label source</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // is either &quot;config&quot; or &quot;dynamic&quot;. Value is 1 while blocked, removed when</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // unblocked (set to 0 and the label combination is dropped).</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    BlockedPeer </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">metrics</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Gauge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> `metrics_labels:&quot;peer_id,source&quot;`</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Metric names (using the existing <code>p2p</code> subsystem):</p><table tabindex="0"><thead><tr><th>Metric</th><th>Type</th><th>Labels</th><th>Description</th></tr></thead><tbody><tr><td><code>&lt;ns&gt;_p2p_gater_blocked_peers_total</code></td><td>Gauge</td><td>—</td><td>Current count of blocked peers</td></tr><tr><td><code>&lt;ns&gt;_p2p_gater_blocked_peer</code></td><td>Gauge</td><td><code>peer_id</code>, <code>source</code></td><td>1 if the peer is blocked; label is removed on unblock</td></tr></tbody></table><p>The <code>BlockedPeer</code> gauge uses a <code>peer_id</code> label containing the full libp2p peer ID string (e.g. <code>12D3KooW...</code>). This allows operators to directly identify blocked peers from Prometheus/Grafana without needing to correlate with logs.</p><p><code>GaterMetrics</code> is constructed in <code>PrometheusMetrics</code> and its nop variant in <code>NopMetrics</code>. <code>TTLConnectionGater</code> calls <code>metrics.BlockedPeersTotal.Set(n)</code> and <code>metrics.BlockedPeer.With(&quot;peer_id&quot;, id.String(), &quot;source&quot;, string(record.Source)).Set(1)</code> after every block/unblock operation and after each sweep tick.</p><p>On unblock, set the gauge to 0:</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">metrics.BlockedPeer.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">With</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;peer_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, id.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">String</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;source&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(record.Source)).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><p>Add to <code>config.P2PConfig</code>:</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// GaterBlockTTL is the default TTL for dynamically blocked peers.</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// A value of 0 disables TTL (blocks are permanent unless explicitly unblocked).</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Default: 1h.</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GaterBlockTTL    time.Duration </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`toml:&quot;gater_block_ttl&quot;`</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// GaterSweepInterval controls how often expired blocks are pruned at runtime.</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Default: 5m.</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GaterSweepInterval time.Duration </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`toml:&quot;gater_sweep_interval&quot;`</span></span></code></pre></div><h3 id="client-wiring-changes" tabindex="-1"><code>Client</code> wiring changes <a class="header-anchor" href="#client-wiring-changes" aria-label="Permalink to &quot;`Client` wiring changes&quot;">​</a></h3><ul><li><code>Client.gater</code> field type changes from <code>*conngater.BasicConnectionGater</code> to <code>*TTLConnectionGater</code>.</li><li><code>Client.ConnectionGater()</code> return type changes accordingly (or returns the inner gater for use with <code>libp2p.ConnectionGater()</code>).</li><li><code>setupBlockedPeers</code> and <code>setupAllowedPeers</code> are replaced by calls to <code>TTLConnectionGater.BlockPeerWithTTL</code> and <code>TTLConnectionGater.UnblockPeer</code>.</li><li><code>GaterMetrics</code> is passed into <code>TTLConnectionGater</code> at construction time, sourced from the same <code>PrometheusMetrics</code> / <code>NopMetrics</code> call that provides <code>Metrics</code> to the client.</li></ul><h3 id="migration" tabindex="-1">Migration <a class="header-anchor" href="#migration" aria-label="Permalink to &quot;Migration&quot;">​</a></h3><p>No explicit migration needed. On first boot after upgrade:</p><ul><li>The new <code>/p2p/gater/ttl/</code> namespace is empty.</li><li>The old <code>BasicConnectionGater</code> entries in the datastore still exist but are no longer read by ev-node. They remain as inert bytes until a future cleanup pass or datastore wipe.</li><li>Config blocks are re-applied fresh from <code>conf.BlockedPeers</code> with permanent TTL.</li></ul><p>This means any stale legacy blocks are silently dropped on the first upgrade boot, which is the desired recovery behavior for nodes in the broken state described in evstack/ev-node#3267.</p><h3 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h3><ul><li>Unit tests for <code>TTLConnectionGater</code>: block, expiry check, sweep, reconciliation with mixed permanent + expiring entries.</li><li>Unit tests for <code>GaterMetrics</code>: verify gauge values reflect block/unblock/sweep transitions.</li><li>Integration test: create a client with stale gater entries in the datastore (simulating the legacy state), start a new client, verify the stale peers are not blocked.</li><li>Existing <code>pkg/p2p</code> tests must continue to pass unchanged.</li></ul><h3 id="breaking-changes" tabindex="-1">Breaking changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking changes&quot;">​</a></h3><p>None. This is an internal implementation change. The gater datastore key space changes, but the old keys are simply ignored (not deleted) so the change is safe to roll back by reverting the binary — the old code will re-read its own namespace and apply whatever was last written there.</p><p>New Prometheus metrics are additive and do not affect existing dashboards or alerts.</p><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Proposed</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Nodes that accumulated stale block entries automatically recover on upgrade without operator intervention.</li><li>Dynamic bans (e.g., for misbehaviour) now expire, preventing permanent peer isolation caused by transient issues.</li><li>Operators can see exactly which peers are blocked and why at startup (logs) and at runtime (Prometheus metrics).</li><li>Config-driven blocks (<code>p2p.blocked_peers</code>) remain permanent as long as they are in config, matching operator intent.</li><li>Prometheus metrics enable alerting on unexpected blocklist growth and identify specific blocked peer IDs without log scraping.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>A peer that is dynamically banned for genuine misbehaviour will be unbanned after the TTL elapses and could reconnect. Operators who want permanent bans must add the peer to <code>p2p.blocked_peers</code> in config.</li><li>Adds a new datastore namespace and a background goroutine, slightly increasing operational complexity.</li><li>The <code>BlockedPeer</code> gauge with a <code>peer_id</code> label has high cardinality if many peers are blocked simultaneously. In practice the blocklist is expected to remain small (&lt; 100 entries), so this is acceptable.</li></ul><h3 id="neutral" tabindex="-1">Neutral <a class="header-anchor" href="#neutral" aria-label="Permalink to &quot;Neutral&quot;">​</a></h3><ul><li>Old <code>BasicConnectionGater</code> datastore entries are abandoned in place. They do not affect correctness but consume a small amount of disk space until the datastore is pruned or wiped.</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>evstack/ev-node#3267 — production incident on edennet-2 that motivated this ADR</li><li><a href="https://github.com/libp2p/go-libp2p/tree/master/p2p/net/conngater" target="_blank" rel="noreferrer">go-libp2p BasicConnectionGater</a></li><li><code>pkg/p2p/client.go</code> — current gater construction and peer block/allow helpers</li><li><code>pkg/p2p/metrics.go</code> — existing Prometheus metrics pattern for this package</li></ul>',84)])])}]]);export{t as __pageData,n as default};
